import React, { useEffect, useState } from "react";
import { Trash2, Pencil, Plus } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const API = "http://localhost:5000/api/links";

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [name, setName] = useState("");
  const [parent, setParent] = useState("");
  const [order, setOrder] = useState(0);
  const [isActive, setIsActive] = useState(true);
  const [editingId, setEditingId] = useState(null);

  /* FETCH LINKS */
  const fetchLinks = async () => {
    try {
      const res = await fetch(API);
      const data = await res.json();
      setLinks(data);
    } catch (error) {
      console.error("Fetch error:", error);
    }
  };

  useEffect(() => {
    fetchLinks();
  }, []);

  /* SUBMIT */
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!name.trim()) return;

    try {
      if (editingId) {
        await fetch(`${API}/${editingId}`, {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            name,
            parent: parent || null,
            order,
            isActive,
          }),
        });
      } else {
        await fetch(API, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            name,
            parent: parent || null,
            order,
            isActive,
          }),
        });
      }

      resetForm();
      fetchLinks();
    } catch (error) {
      console.error("Submit error:", error);
    }
  };

  const handleEdit = (link) => {
    setName(link.name);
    setParent(link.parent || "");
    setOrder(link.order);
    setIsActive(link.isActive);
    setEditingId(link._id);
  };

  const handleDelete = async (id) => {
    try {
      await fetch(`${API}/${id}`, {
        method: "DELETE",
      });

      fetchLinks();
    } catch (error) {
      console.error("Delete error:", error);
    }
  };

  const resetForm = () => {
    setName("");
    setParent("");
    setOrder(0);
    setIsActive(true);
    setEditingId(null);
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        <div className={design.headerWrapper}>
          <div>
            <h1 className={design.title}>Navigation Links</h1>
            <p className={design.subtitle}>
              Manage main navigation links shown on the public website.
            </p>
          </div>
        </div>

        <div className={design.card}>
          <div className={design.formSection}>
            <form
              onSubmit={handleSubmit}
              className="grid grid-cols-1 md:grid-cols-4 gap-4"
            >
              <input
                type="text"
                placeholder="Link Name"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className={design.input}
              />

              <select
                value={parent}
                onChange={(e) => setParent(e.target.value)}
                className={design.input}
              >
                <option value="">Main Menu</option>
                {links
                  .filter((l) => !l.parent)
                  .map((link) => (
                    <option key={link._id} value={link._id}>
                      {link.name}
                    </option>
                  ))}
              </select>

              <input
                type="number"
                placeholder="Order"
                value={order}
                onChange={(e) => setOrder(Number(e.target.value))}
                className={design.input}
              />

              <motion.button
                whileTap={{ scale: 0.95 }}
                type="submit"
                className={design.buttonPrimary}
              >
                <Plus size={16} />
                {editingId ? "Update" : "Add"}
              </motion.button>
            </form>
          </div>

          {/* TABLE */}
          <div className={design.tableWrapper}>
            <div className={design.tableHeader}>
              <div>Name</div>
              <div className="text-right">Actions</div>
            </div>

            <AnimatePresence>
              {links.length === 0 ? (
                <div className={design.emptyState}>
                  No links created yet.
                </div>
              ) : (
                links.map((link) => (
                  <motion.div
                    key={link._id}
                    initial={{ opacity: 0, y: 8 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0 }}
                    className={design.tableRow}
                  >
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-4">
                        <span className="font-medium text-slate-800">
                          {link.name}
                        </span>

                        <span
                          className={
                            link.isActive
                              ? design.badge
                              : "inline-flex px-3 py-1 rounded-full text-xs bg-red-100 text-red-600"
                          }
                        >
                          {link.isActive ? "Active" : "Inactive"}
                        </span>
                      </div>

                      <div className="flex gap-4">
                        <button
                          onClick={() => handleEdit(link)}
                          className="text-slate-500 hover:text-indigo-600 transition"
                        >
                          <Pencil size={18} />
                        </button>

                        <button
                          onClick={() => handleDelete(link._id)}
                          className="text-slate-500 hover:text-red-600 transition"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>
                  </motion.div>
                ))
              )}
            </AnimatePresence>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LinkHome;
